import{_ as p,c as A}from"./app.90a21e26.js";const I={},P=A('<h1 id="\u7B54\u7591\u89E3\u60D1\u7B2C\u56DB\u671F" tabindex="-1"><a class="header-anchor" href="#\u7B54\u7591\u89E3\u60D1\u7B2C\u56DB\u671F" aria-hidden="true">#</a> \u7B54\u7591\u89E3\u60D1\u7B2C\u56DB\u671F</h1><p>\u4F60\u597D\uFF0C\u6211\u662F\u8339\u70B3\u665F\u3002</p><p>\u4ECA\u5929\u7684\u201C\u7B54\u7591\u89E3\u60D1\u201D\u6587\u7AE0\uFF0C\u6211\u5C06\u9488\u5BF9 API \u81EA\u52A8\u5316\u6D4B\u8BD5\u548C\u4EE3\u7801\u7EA7\u6D4B\u8BD5\u8FD9\u4E24\u4E2A\u7CFB\u5217 6 \u7BC7\u6587\u7AE0\u4E2D\u7684\u95EE\u9898\uFF0C\u548C\u4F60\u5C55\u5F00\u5206\u4EAB\u3002</p><p>\u6211\u8FD8\u662F\u4F1A\u5148\u7B80\u5355\u6982\u62EC\u4E0B\u6BCF\u7BC7\u6587\u7AE0\u7684\u5185\u5BB9\uFF0C\u5E76\u7ED9\u51FA\u6587\u7AE0\u94FE\u63A5\uFF0C\u5E2E\u52A9\u4F60\u590D\u4E60\u76F8\u5E94\u7684\u5185\u5BB9\u3002\u540C\u65F6\uFF0C\u5982\u679C\u4F60\u518D\u6B21\u9605\u8BFB\u65F6\u8FD8\u6709\u54EA\u4E9B\u7591\u95EE\u7684\u8BDD\uFF0C\u4E5F\u6B22\u8FCE\u4F60\u5728\u6587\u7AE0\u4E0B\u9762\u7EE7\u7EED\u7559\u8A00\u3002\u6211\u4F1A\u4E00\u76F4\u5173\u6CE8\u7740\u4F60\u7684\u5B66\u4E60\u60C5\u51B5\uFF0C\u5E0C\u671B\u53EF\u4EE5\u626B\u6E05\u8F6F\u4EF6\u6D4B\u8BD5\u7CBE\u8FDB\u9053\u8DEF\u4E0A\u7684\u969C\u788D\u3002</p><p>\u73B0\u5728\uFF0C\u6211\u4EEC\u5C31\u5F00\u59CB\u4ECA\u5929\u7684\u4E3B\u9898\u5427\u3002</p><p><strong>\u95EE\u9898\u4E00\uFF1A\u5B9E\u9645\u9879\u76EE\u4E2D\uFF0C\u5F80\u5F80\u4F1A\u5B58\u5728\u6309\u65F6\u5E8F\u7684 API \u8C03\u7528\u4EE5\u53CA\u5F02\u6B65 API \u8C03\u7528\uFF0C\u8FD9\u7C7B API \u6D4B\u8BD5\u8981\u5982\u4F55\u5F00\u5C55\uFF1F</strong></p><p>\u5728\u4E13\u680F\u7684\u7B2C 22 \u7BC7\u6587\u7AE0\u300A\u4ECE 0 \u5230 1\uFF1AAPI \u6D4B\u8BD5\u600E\u4E48\u505A\uFF1F\u5E38\u7528 API \u6D4B\u8BD5\u5DE5\u5177\u7B80\u4ECB\u300B\u4E2D\uFF0C\u6211\u4EE5\u57FA\u4E8E\u4E3B\u6D41 Spring Boot \u6846\u67B6\u5F00\u53D1\u7684\u7B80\u5355 Restful API \u4E3A\u4F8B\uFF0C\u5206\u522B\u4ECB\u7ECD\u5982\u4F55\u4F7F\u7528 cURL \u548C Postman \u5BF9\u5176\u8FDB\u884C\u6700\u57FA\u672C\u7684\u529F\u80FD\u6D4B\u8BD5\uFF0C\u5E0C\u671B\u53EF\u4EE5\u8BA9\u4F60\u5148\u5BF9 API \u6D4B\u8BD5\u6709\u4E2A\u611F\u6027\u8BA4\u8BC6\u3002\u53E6\u5916\uFF0C\u5728\u8FD9\u7BC7\u6587\u7AE0\u4E2D\uFF0C\u6211\u8FD8\u548C\u4F60\u5206\u4EAB\u4E86\u76EE\u524D\u4E00\u4E9B\u5E38\u89C1\u7684\u5178\u578B\u590D\u6742\u573A\u666F\uFF0C\u4EE5\u53CA\u76F8\u5E94\u7684\u6D4B\u8BD5\u601D\u8DEF\u548C\u65B9\u6CD5\u3002</p><p>\u800C\u5728\u6587\u7AE0\u6700\u540E\uFF0C\u6211\u5E0C\u671B\u4F60\u601D\u8003\u7684\u662F\u5B9E\u9645\u9879\u76EE\u4E2D\u5F80\u5F80\u4F1A\u5B58\u5728\u6309\u65F6\u5E8F\u7684 API \u8C03\u7528\u4EE5\u53CA\u5F02\u6B65 API \u8C03\u7528\uFF0C\u8FD9\u7C7B API \u6D4B\u8BD5\u8981\u5982\u4F55\u5F00\u5C55\uFF1F\u73B0\u5728\uFF0C\u6211\u6765\u8BF4\u8BF4\u6211\u7684\u7ECF\u9A8C\u5427\u3002</p><p>\u6211\u4EEC\u5148\u4E00\u8D77\u770B\u770B\u6309\u65F6\u5E8F\u8C03\u7528\u7684 API \u5E8F\u5217\u7684\u6D4B\u8BD5\u573A\u666F\u3002</p><p>\u5BF9\u4E8E\u6B64\u7C7B\u6D4B\u8BD5\uFF0C\u6211\u4E00\u822C\u5EFA\u8BAE\u901A\u8FC7 GUI \u64CD\u4F5C\u6765\u5F55\u5236 API \u7684\u8C03\u7528\u3002\u6BD4\u5982\uFF0C\u5728\u542F\u7528 Fiddler \u7684\u60C5\u51B5\u4E0B\uFF0C\u901A\u8FC7 GUI \u6765\u5B8C\u6210\u4E1A\u52A1\u64CD\u4F5C\uFF0C\u968F\u540E\u53BB\u5206\u6790 Fiddler \u6293\u53D6\u5230\u7684\u540E\u7AEF API \u8BF7\u6C42\u987A\u5E8F\uFF0C\u7136\u540E\u4EE5\u6B64\u6765\u5F00\u53D1 API \u6D4B\u8BD5\u7528\u4F8B\u3002</p><p>\u5F00\u53D1\u6D4B\u8BD5\u7528\u4F8B\u7684\u8FC7\u7A0B\u4E2D\u8FD8\u9700\u8981\u7279\u522B\u5173\u6CE8\u524D\u540E\u4E24\u4E2A API \u8C03\u7528\u4E4B\u95F4\u7684\u6570\u636E\u4F20\u9012\uFF0C\u6BD4\u5982\u9700\u8981\u5C06\u524D\u4E00\u4E2A API \u8C03\u7528\u8FD4\u56DE\u7684 response \u4E2D\u7684\u67D0\u4E2A\u503C\u4F5C\u4E3A\u53C2\u6570\u4F20\u9012\u7ED9\u4E0B\u4E00\u4E2A API \u8C03\u7528\u3002</p><p>\u5176\u6B21\u662F\u5F02\u6B65 API \u7684\u6D4B\u8BD5\u3002\u5BF9\u4E8E\u5F02\u6B65 API \u6D4B\u8BD5\u7684\u573A\u666F\uFF0C\u6211\u4EEC\u5F80\u5F80\u5148\u4F1A\u91C7\u53D6\u201C\u53EA\u9A8C\u8BC1\u5176\u662F\u5426\u53D1\u8D77\u4E86\u6B63\u786E\u7684\u8C03\u7528\uFF0C\u800C\u4E0D\u76F4\u63A5\u9A8C\u8BC1\u64CD\u4F5C\u7ED3\u679C\u201D\u7684\u65B9\u5F0F\u3002\u6BD4\u5982\uFF0C\u4F60\u7684\u88AB\u6D4B API \u662F\u4E00\u4E2A\u5F02\u6B65\u64CD\u4F5C\u7684 API\uFF0C\u90A3\u4E48\u6211\u53EA\u4F1A\u53BB\u9A8C\u8BC1\u8FD9\u4E2A API \u662F\u5426\u6309\u7167\u9884\u671F\u53D1\u8D77\u4E86\u6B63\u786E\u7684\u5F02\u6B65\u8C03\u7528\u8BF7\u6C42\uFF0C\u800C\u4E0D\u4F1A\u76F4\u63A5\u53BB\u9A8C\u8BC1\u5F02\u6B65\u64CD\u4F5C\u7684\u7ED3\u679C\u3002\u5982\u679C\u8FD9\u7C7B\u6D4B\u8BD5\u5168\u90E8\u901A\u8FC7\u540E\uFF0C\u6211\u4EEC\u624D\u4F1A\u8003\u8651\u771F\u6B63\u9A8C\u8BC1\u5F02\u6B65\u64CD\u4F5C\u7ED3\u679C\u7684\u6D4B\u8BD5\u7528\u4F8B\u3002</p><p>\u4E3E\u4E2A\u5B9E\u9645\u7684\u4F8B\u5B50\uFF0C\u5047\u8BBE\u4F60\u7684\u88AB\u6D4B API A \u5B8C\u6210\u7684\u662F\u4E0B\u8BA2\u5355\u7684\u64CD\u4F5C\u3002\u8FD9\u4E2A API A \u5B8C\u6210\u4E0B\u8BA2\u5355\u64CD\u4F5C\u8981\u901A\u8FC7\u8C03\u7528\u53E6\u5916\u4E00\u4E2A API B \u5C06\u8BA2\u5355\u4FE1\u606F\u5199\u5165\u5230\u6D88\u606F\u961F\u5217\u4E2D\u53BB\u3002\u800C\u771F\u6B63\u4E0B\u8BA2\u5355\u6210\u529F\u6307\u7684\u662F\u6D88\u606F\u961F\u5217\u4E2D\u7684\u6D88\u606F\u88AB\u540E\u7EED\u670D\u52A1\u6B63\u786E\u5904\u7406\u5E76\u4E14\u6210\u529F\u4E86\u3002\u6B64\u65F6\uFF0C\u8FD9\u91CC\u7684\u540E\u7EED\u6D88\u606F\u5904\u7406\u5C31\u662F\u5F02\u6B65\u7684\u64CD\u4F5C\u4E86\u3002</p><p>\u90A3\u4E48\uFF0C\u5F53\u6211\u4EEC\u8981\u6D4B\u8BD5\u8FD9\u4E2A API A \u7684\u65F6\u5019\uFF0C\u6211\u4EEC\u53EA\u9700\u8981\u9A8C\u8BC1\u5B83\u662F\u5426\u6B63\u786E\u5730\u53D1\u8D77\u4E86\u5BF9 API B \u7684\u8C03\u7528\u5373\u53EF\uFF0C\u800C\u4E0D\u7528\u5173\u5FC3 API B \u7684\u5177\u4F53\u884C\u4E3A\u7ED3\u679C\u3002</p><p>\u4E5F\u5C31\u662F\u8BF4\uFF0C\u6211\u4EEC\u53EA\u5173\u6CE8 API A \u662F\u5426\u4EE5\u6B63\u786E\u7684\u53C2\u6570\u8C03\u7528\u4E86 API B \u5373\u53EF\uFF0C\u800C\u65E0\u9700\u5173\u6CE8 API B \u662F\u5426\u6B63\u786E\u5730\u6267\u884C\u4E86\u5C06\u8BA2\u5355\u4FE1\u606F\u5199\u5165\u6D88\u606F\u961F\u5217\u7684\u64CD\u4F5C\uFF0C\u66F4\u4E0D\u7528\u5173\u6CE8\uFF0C\u6D88\u606F\u961F\u5217\u4E2D\u7684\u6D88\u606F\u88AB\u5F02\u6B65\u5904\u7406\u7684\u7ED3\u679C\u3002</p><p>\u6CE8\u610F\u8FD9\u91CC\u7684\u6D4B\u8BD5\u91CD\u70B9\uFF0C\u5E94\u8BE5\u66F4\u591A\u5730\u653E\u5728\u524D\u9762\u7684\u90E8\u5206\uFF0C\u800C\u771F\u6B63\u9A8C\u8BC1\u5F02\u6B65\u64CD\u4F5C\u7ED3\u679C\u7684\u6D4B\u8BD5\u5728\u8D44\u6E90\u6709\u9650\u7684\u60C5\u51B5\u4E0B\u53EA\u9700\u8986\u76D6\u6700\u5178\u578B\u7684\u573A\u666F\u5373\u53EF\u3002</p><p><strong>\u95EE\u9898\u4E8C\uFF1A\u5BF9\u57FA\u4E8E\u914D\u7F6E\u6587\u4EF6\u7684 API \u6D4B\u8BD5\u6846\u67B6\uFF0C\u4F60\u6709\u54EA\u4E9B\u770B\u6CD5\u5462\uFF1F</strong></p><p>\u5728\u4E13\u680F\u7684\u7B2C 23 \u7BC7\u6587\u7AE0\u300A\u77E5\u5176\u7136\u77E5\u5176\u6240\u4EE5\u7136\uFF1A\u804A\u804A API \u81EA\u52A8\u5316\u6D4B\u8BD5\u6846\u67B6\u7684\u524D\u4E16\u4ECA\u751F\u300B\u4E2D\uFF0C\u6211\u548C\u4F60\u5206\u4EAB\u4E86 API \u81EA\u52A8\u5316\u6D4B\u8BD5\u6846\u67B6\u7684\u53D1\u5C55\u5386\u7A0B\uFF0C\u5E2E\u52A9\u4F60\u7406\u89E3 API \u6D4B\u8BD5\u662F\u5982\u4F55\u4E00\u6B65\u4E00\u6B65\u5730\u53D1\u5C55\u6210\u4ECA\u5929\u7684\u6837\u5B50\uFF0C\u5E0C\u671B\u53EF\u4EE5\u4EE5\u8FD9\u79CD\u201C\u77E5\u5176\u6240\u4EE5\u7136\u201D\u7684\u65B9\u5F0F\u52A0\u6DF1\u4F60\u5BF9 API \u81EA\u52A8\u5316\u6D4B\u8BD5\u7684\u7406\u89E3\u3002</p><p>\u800C\u5728\u8FD9\u7BC7\u6587\u7AE0\u6700\u540E\uFF0C\u6211\u63D0\u5230\u4E86\u57FA\u4E8E\u914D\u7F6E\u6587\u4EF6\u7684 API \u6D4B\u8BD5\u6846\u67B6\uFF0C\u6BD4\u5982\u5178\u578B\u7684 HttpRunner\u3002\u5728\u6B64\u7C7B API \u6D4B\u8BD5\u6846\u67B6\u7684\u652F\u6301\u4E0B\uFF0C\u6D4B\u8BD5\u7528\u4F8B\u672C\u8EAB\u5F80\u5F80\u5C31\u662F\u7EAF\u7CB9\u7684\u914D\u7F6E\u6587\u4EF6\u4E86\u3002\u5982\u679C\u4F60\u7528\u8FC7\u8FD9\u4E2A\u6846\u67B6\u7684\u8BDD\uFF0C\u6211\u5E0C\u671B\u4F60\u53EF\u4EE5\u8C08\u8C08\u4F60\u7684\u770B\u6CD5\u3002</p><p>\u5BF9\u4E8E\u57FA\u4E8E\u914D\u7F6E\u6587\u4EF6\u7684 API \u6D4B\u8BD5\u6846\u67B6\u7684\u786E\u662F\u4E2A\u4E0D\u9519\u7684\u65B9\u5411\uFF0C\u5C24\u5176\u662F\u56FD\u5185\u7684\u5F00\u6E90\u6846\u67B6 HttpRunner \u66F4\u662F\u63A8\u52A8\u4E86\u8FD9\u79CD\u6D4B\u8BD5\u6846\u67B6\u7684\u666E\u53CA\u3002</p><p>\u57FA\u4E8E\u914D\u7F6E\u6587\u4EF6\u7684 API \u6D4B\u8BD5\u6846\u67B6\u7684\u4F18\u52BF\uFF0C\u53EF\u4EE5\u5F52\u7EB3\u4E3A\u4EE5\u4E0B\u4E09\u65B9\u9762\uFF1A</p><p>\u964D\u4F4E\u4E86\u6D4B\u8BD5\u7528\u4F8B\u5F00\u53D1\u7684\u95E8\u69DB\uFF0C\u4F7F\u5F97\u5B8C\u5168\u6CA1\u6709\u4EE3\u7801\u57FA\u7840\u7684\u540C\u5B66\u4E5F\u53EF\u4EE5\u5F88\u5BB9\u6613\u5730\u5B8C\u6210 API \u6D4B\u8BD5\uFF1B</p><p>\u53EF\u4EE5\u5F88\u65B9\u4FBF\u5730\u5C06 API \u529F\u80FD\u6D4B\u8BD5\u7528\u4F8B\u76F4\u63A5\u8F6C\u6362\u6210 API \u6027\u80FD\u6D4B\u8BD5\u7684\u7528\u4F8B\uFF08HttpRunner \u53EF\u4EE5\u4F7F\u7528 lucust \u76F4\u63A5\u5B9E\u73B0\u8FD9\u6837\u7684\u8F6C\u6362\uFF09\uFF1B</p><p>\u540C\u65F6\uFF0CHttpRunner \u8FD9\u7C7B\u5DE5\u5177\u8FD8\u652F\u6301\u76F4\u63A5\u4ECE\u7F51\u7EDC\u8F6C\u53D1\u5DE5\u5177\u5F97\u5230\u7684 HAR \u4E2D\u63D0\u53D6 API \u8C03\u7528\u7684\u6D4B\u8BD5\u7528\u4F8B\uFF0C\u8FDB\u4E00\u6B65\u964D\u4F4E\u4E86 API \u6D4B\u8BD5\u7528\u4F8B\u7684\u5F00\u53D1\u6210\u672C\u3002</p><p>\u6240\u4EE5\uFF0C\u57FA\u4E8E\u914D\u7F6E\u6587\u4EF6\u7684 API \u6D4B\u8BD5\u6846\u67B6\u5F88\u53D7\u521D\u5B66\u8005\u7684\u6B22\u8FCE\u3002</p><p>\u4F46\u662F\uFF0C\u4E3A\u4E86\u5B8C\u6210\u4E00\u4E9B\u590D\u6742\u573A\u666F\u7684\u6D4B\u8BD5\u7528\u4F8B\u8BBE\u8BA1\u4EE5\u53CA\u590D\u6742\u7684\u7ED3\u679C\u5224\u65AD\uFF0C\u4F60\u8FD8\u662F\u9700\u8981\u5177\u5907\u57FA\u672C\u7684\u4EE3\u7801\u80FD\u529B\uFF0C\u4EE5\u5B8C\u6210\u8FD9\u4E9B\u590D\u6742\u573A\u666F\u7684\u6D4B\u8BD5\u5B9E\u73B0\u3002\u6BD4\u5982\uFF0CHttpRunner \u5C31\u4F1A\u6D89\u53CA\u5230\u4F7F\u7528 debugtalk.py \u6765\u5B9E\u73B0 hook \u51FD\u6570\u7684\u529F\u80FD\u6269\u5C55\u3002</p><p>\u4E5F\u5C31\u662F\u8BF4\uFF0C\u5B8C\u5168\u4E0D\u5199\u4EE3\u7801\u7684 API \u6D4B\u8BD5\u53EA\u80FD\u8986\u76D6\u5927\u90E8\u5206\u7684\u7B80\u5355\u6D4B\u8BD5\u573A\u666F\uFF0C\u5982\u679C\u4F60\u8981\u641E\u5B9A\u590D\u6742\u573A\u666F\u7684 API \u6D4B\u8BD5\u7684\u8BDD\uFF0C\u4F60\u662F\u8981\u5FC5\u987B\u638C\u63E1\u4E00\u4E9B\u57FA\u672C\u7684\u5F00\u53D1\u6280\u80FD\uFF0C\u8FD9\u91CC\u6CA1\u6709\u4EFB\u4F55\u6377\u5F84\u53EF\u8D70\u3002</p><p>\u53E6\u5916\uFF0C\u5F88\u591A\u8BFB\u8005\u7684\u7559\u8A00\u4E5F\u5F88\u7CBE\u5F69\uFF0C\u6211\u8FD9\u91CC\u7279\u5730\u9009\u53D6\u4E86\u4E24\u6761\u4F9B\u5927\u5BB6\u53C2\u8003\u3002\u4ECE Cynthia \u7684\u7559\u8A00\u4E2D\uFF0C\u6211\u770B\u5F97\u51FA\u5979\u5DF2\u7ECF\u5B8C\u5168\u4E60\u5F97\u4E86\u8FD9\u7BC7\u6587\u7AE0\u4E2D\u63CF\u8FF0\u7684\u65B9\u6CD5\u7684\u7CBE\u9AD3\uFF0C\u8FD9\u4E5F\u6B63\u662F\u6211\u60F3\u8981\u4F20\u8FBE\u7ED9\u4F60\u7684\u6700\u6838\u5FC3\u7684\u5185\u5BB9\u3002</p><p><img src="https://static001.geekbang.org/resource/image/a6/ba/a67715406c2a7ae6e9bb98d2e3198eba.png" alt=""></p><p>Martin \u5728\u7559\u8A00\u7684\u540E\u534A\u90E8\u5206\u4E2D\u63D0\u5230\uFF0C\u901A\u8FC7 HttpRunner \u6765\u5B9E\u73B0\u8F7B\u91CF\u7EA7\u7684 API \u6D4B\u8BD5\u7684\u786E\u662F\u4E2A\u597D\u65B9\u6CD5\uFF0C\u4E5F\u6700\u5927\u7A0B\u5EA6\u5730\u53D1\u6325\u4E86 HttpRunner \u7684\u4EF7\u503C\u3002\u4F46\u662F\uFF0C\u7559\u8A00\u524D\u534A\u90E8\u5206\u7684\u201CPostman \u8F6C Python \u6216\u8005 Java\u201D\u7684\u89C2\u70B9\u6211\u5E76\u4E0D\u662F\u5F88\u8BA4\u540C\u3002\u5176\u5B9E\uFF0CPostman \u662F\u6709\u76F4\u63A5\u4EE3\u7801\u8F6C\u6362\u529F\u80FD\u7684\uFF0C\u800C\u4E14\u652F\u6301\u5404\u79CD\u8BED\u8A00\u7684\u5404\u79CD\u6846\u67B6\uFF0C\u57FA\u672C\u53EF\u4EE5\u5B9E\u73B0\u4E00\u952E\u64CD\u4F5C\uFF0C\u6240\u4EE5\uFF0C\u5176\u5B9E\u5F88\u591A\u6CA1\u6709\u91C7\u7528 HttpRunner \u7684\u4F01\u4E1A\u90FD\u8FD8\u5728\u666E\u904D\u4F7F\u7528\u8FD9\u4E2A\u65B9\u6CD5\u3002</p><p><img src="https://static001.geekbang.org/resource/image/5d/9c/5dc1be96cdacac1a510d10019e1cd59c.png" alt=""></p><p><strong>\u95EE\u9898\u4E09\uFF1A\u5982\u679C\u65E0\u6CD5\u901A\u8FC7 API Gateway \u65B9\u6CD5\u5F97\u5230\u5951\u7EA6\u7684\u8BDD\uFF0C\u5E94\u8BE5\u91C7\u7528\u4EC0\u4E48\u65B9\u6CD5\u6765\u89E3\u51B3\u5462\uFF1F</strong></p><p>\u5728\u4E13\u680F\u7684\u7B2C 24 \u7BC7\u6587\u7AE0\u300A\u7D27\u8DDF\u65F6\u4EE3\u6B65\u4F10\uFF1A\u5FAE\u670D\u52A1\u6A21\u5F0F\u4E0B API \u6D4B\u8BD5\u8981\u600E\u4E48\u505A\uFF1F\u300B\u4E2D\uFF0C\u6211\u548C\u4F60\u5206\u4EAB\u4E86\u5FAE\u670D\u52A1\u6A21\u5F0F\u4E0B\u7684 API \u6D4B\u8BD5\uFF0C\u65E8\u5728\u5E2E\u52A9\u4F60\u8BA4\u6E05\u5E9E\u5927\u7684\u6D4B\u8BD5\u7528\u4F8B\u6570\u91CF\u3001\u5FAE\u670D\u52A1\u4E4B\u95F4\u7684\u76F8\u4E92\u8026\u5408\u8FD9\u4E24\u4E2A\u95EE\u9898\u7684\u672C\u8D28\uFF0C\u4EE5\u66F4\u597D\u5730\u5F00\u5C55\u6D4B\u8BD5\u3002\u6240\u4EE5\uFF0C\u6211\u4ECA\u5929\u5206\u4EAB\u8FD9\u4E2A\u4E3B\u9898\u7684\u76EE\u7684\u5C31\u662F\uFF0C\u5E2E\u4F60\u7406\u89E3\u8FD9\u4E24\u4E2A\u95EE\u9898\u7684\u672C\u8D28\uFF0C\u4EE5\u53CA\u5982\u4F55\u57FA\u4E8E\u6D88\u8D39\u8005\u5951\u7EA6\u7684\u65B9\u6CD5\u6765\u89E3\u51B3\u8FD9\u4E24\u4E2A\u96BE\u9898\u3002</p><p>\u800C\u5728\u4ECA\u5929\u8FD9\u7BC7\u6587\u7AE0\u6700\u540E\uFF0C\u6211\u5E0C\u671B\u4F60\u601D\u8003\u7684\u662F\uFF1A\u57FA\u4E8E\u6D88\u8D39\u8005\u5951\u7EA6\u7684 API \u6D4B\u8BD5\u4E2D\uFF0C\u5BF9\u4E8E\u90A3\u4E9B\u65B0\u5F00\u53D1\u7684 API\uFF0C\u6216\u8005\u52A0\u4E86\u65B0\u529F\u80FD\u7684 API\uFF0C\u7531\u4E8E\u4E4B\u524D\u90FD\u6CA1\u6709\u5B9E\u9645\u7684\u6D88\u8D39\u8005\uFF0C\u6240\u4EE5\u4F60\u65E0\u6CD5\u901A\u8FC7 API Gateway \u65B9\u6CD5\u5F97\u5230\u5951\u7EA6\u3002\u5BF9\u4E8E\u8FD9\u79CD\u60C5\u51B5\uFF0C\u4F60\u4F1A\u91C7\u7528\u4EC0\u4E48\u65B9\u6CD5\u6765\u89E3\u51B3\u5462\uFF1F</p><p>\u4ECE\u6211\u7684\u7ECF\u9A8C\u6765\u770B\uFF0C\u56E0\u4E3A\u7F3A\u4E4F\u5951\u7EA6\uFF0C\u6240\u4EE5\u8FD8\u662F\u4F1A\u91C7\u7528\u4F20\u7EDF\u7684 API \u6D4B\u8BD5\u65B9\u6CD5\uFF0C\u4E5F\u5C31\u662F\u6839\u636E API \u8BBE\u8BA1\u6587\u6863\u6765\u8BBE\u8BA1\u6D4B\u8BD5\u7528\u4F8B\u3002</p><p>\u8FD9\u65F6\uFF0C\u6211\u4EEC\u91C7\u53D6\u7684 API \u6D4B\u8BD5\u7B56\u7565\u662F\uFF1A</p><p>\u5BF9\u4E8E\u5DF2\u7ECF\u4E0A\u7EBF\u7684 API \u6211\u4EEC\u4F1A\u901A\u8FC7\u5951\u7EA6\u6D4B\u8BD5\u6765\u4FDD\u8BC1\u8D28\u91CF\uFF1B \u800C\u5BF9\u4E8E\u65B0\u7684 API\uFF0C\u6216\u8005\u662F\u52A0\u4E86\u65B0\u529F\u80FD\u7684 API\uFF0C\u5219\u8FD8\u662F\u91C7\u7528\u4F20\u7EDF\u7684\u57FA\u4E8E API \u8BBE\u8BA1\u6587\u6863\u6765\u8BBE\u8BA1\u6D4B\u8BD5\u7528\u4F8B\uFF0C\u540C\u65F6\u57FA\u4E8E\u4EE3\u7801\u8986\u76D6\u7387\u6765\u6307\u5BFC\u8865\u5145\u9057\u6F0F\u6D4B\u8BD5\u7528\u4F8B\u7684\u65B9\u5F0F\u6765\u4FDD\u8BC1\u8D28\u91CF\u3002\u5F53\u8FD9\u4E9B\u65B0 API \u4E0A\u7EBF\u8FD0\u884C\u4E86\u4E00\u6BB5\u65F6\u95F4\u540E\uFF0C\u6211\u4EEC\u5C31\u4F1A\u7F29\u5C0F\u6D4B\u8BD5\u7684\u8303\u56F4\uFF0C\u9010\u6E10\u5411\u5951\u7EA6\u6D4B\u8BD5\u8FC7\u6E21\u3002</p><p><strong>\u95EE\u9898\u56DB\uFF1A\u4F60\u6240\u5728\u516C\u53F8\uFF0C\u5728\u8FDB\u884C\u4EE3\u7801\u7EA7\u6D4B\u8BD5\u65F6\uFF0C\u91C7\u7528\u8FC7\u54EA\u4E9B\u65B9\u6CD5\u5462\uFF1F</strong></p><p>\u5728\u4E13\u680F\u7684\u7B2C 25 \u7BC7\u6587\u7AE0\u300A\u4E0D\u7834\u4E0D\u7ACB\uFF1A\u638C\u63E1\u4EE3\u7801\u7EA7\u6D4B\u8BD5\u7684\u57FA\u672C\u7406\u5FF5\u4E0E\u65B9\u6CD5\u300B\u4E2D\uFF0C\u6211\u6839\u636E\u5B9E\u9645\u5DE5\u7A0B\u9879\u76EE\u4E2D\u7684\u5B9E\u8DF5\uFF0C\u603B\u7ED3\u4E86\u4E94\u79CD\u5E38\u89C1\u7684\u4EE3\u7801\u9519\u8BEF\uFF0C\u4EE5\u53CA\u5BF9\u5E94\u7684\u56DB\u5927\u7C7B\u4EE3\u7801\u7EA7\u6D4B\u8BD5\u65B9\u6CD5\u3002\u8FD9\u91CC\u6211\u8FD8\u60F3\u5728\u591A\u5570\u55E6\u4E00\u53E5\uFF0C\u4EE3\u7801\u7EA7\u6D4B\u8BD5\u7684\u6D4B\u8BD5\u65B9\u6CD5\u4E00\u5B9A\u662F\u4E00\u5957\u6D4B\u8BD5\u65B9\u6CD5\u7684\u96C6\u5408\uFF0C\u800C\u4E0D\u662F\u4E00\u4E2A\u6D4B\u8BD5\u65B9\u6CD5\u3002</p><p>\u800C\u5728\u8FD9\u7BC7\u6587\u7AE0\u6700\u540E\uFF0C\u6211\u5E0C\u671B\u4F60\u5206\u4EAB\u4E00\u4E0B\u4F60\u6240\u5728\u516C\u53F8\uFF0C\u5728\u8FDB\u884C\u4EE3\u7801\u7EA7\u6D4B\u8BD5\u65F6\u91C7\u7528\u8FC7\u54EA\u4E9B\u65B9\u6CD5\uFF0C\u53C8\u662F\u5982\u4F55\u5177\u4F53\u5F00\u5C55\u7684\u3002\u8FD9\u91CC\u6211\u6765\u5206\u4EAB\u4E0B\u6211\u5728 eBay \u7684\u7ECF\u9A8C\u5427\u3002</p><p>\u5728 eBay\uFF0C\u4EE3\u7801\u8D28\u91CF\u4FDD\u969C\u5DF2\u7ECF\u5B8C\u5168\u7EB3\u5165\u4E86 CI/CD \u6D41\u6C34\u7EBF\u3002</p><p>\u9996\u5148\uFF0C\u6211\u4EEC\u57FA\u4E8E Sonar \u542F\u7528\u4E86\u9759\u6001\u4EE3\u7801\u3002\u9664\u4E86\u5728\u4E0A\u4F20 Git \u7684\u65F6\u5019\u89E6\u53D1\u9759\u6001\u626B\u63CF\u5916\uFF0C\u5F00\u53D1\u4EBA\u5458\u5728\u672C\u5730 IDE \u4E2D\u4E5F\u4F1A\u8FDB\u884C\u5B9E\u65F6\u7684\u9759\u6001\u626B\u63CF\uFF0C\u5E76\u53EF\u4EE5\u5B9E\u65F6\u770B\u5230\u5206\u6790\u7ED3\u679C\uFF0C\u8FD9\u6837\u5C31\u53EF\u4EE5\u5728\u4EE3\u7801\u88AB\u9012\u4EA4\u5230\u4EE3\u7801\u4ED3\u5E93\u524D\u5C31\u5DF2\u7ECF\u5B8C\u6210\u4E86\u9884\u68C0\u6D4B\u3002</p><p>\u5176\u5B9E\uFF0C\u6211\u4EEC\u5E76\u6CA1\u6709\u76F4\u63A5\u91C7\u7528\u6807\u51C6\u7684\u4EE3\u7801\u9759\u6001\u626B\u63CF\u7684\u89C4\u5219\u5E93\uFF0C\u800C\u662F\u5220\u9664\u4E86\u5176\u4E2D\u5F88\u591A\u6211\u4EEC\u8BA4\u4E3A\u8FC7\u4E8E\u4E25\u683C\u7684\u89C4\u5219\uFF0C\u540C\u65F6\u52A0\u5165\u4E86\u4E00\u4E9B\u6211\u4EEC\u8BA4\u4E3A\u6BD4\u8F83\u91CD\u8981\u7684\u68C0\u6D4B\u9879\uFF0C\u4F7F\u5F97\u8FD9\u4E2A\u89C4\u5219\u5E93\u66F4\u7B26\u5408\u6211\u4EEC\u7684\u4E1A\u52A1\u573A\u666F\u3002\u4E00\u822C\u60C5\u51B5\u4E0B\uFF0C\u8FD9\u4E9B\u89C4\u5219\u7684\u4FEE\u8BA2\u662F\u7531\u6D4B\u8BD5\u67B6\u6784\u5E08\u7275\u5934\uFF0C\u4E0E\u5F00\u53D1\u4E3B\u7BA1\u548C\u8D44\u6DF1\u7684\u5F00\u53D1\u4EBA\u5458\u4E00\u8D77\u534F\u5546\u51B3\u5B9A\u7684\u3002</p><p>\u8FD9\u91CC\u9700\u8981\u6CE8\u610F\u7684\u662F\uFF0C\u6211\u4EEC\u5E76\u4E0D\u8981\u6C42\u9759\u6001\u626B\u63CF\u4E0A\u62A5\u7684\u6240\u6709\u9519\u8BEF\u90FD\u88AB\u4FEE\u590D\u540E\u624D\u80FD\u53D1\u5E03\uFF0C\u53EA\u8981\u6C42\u89E3\u51B3\u6700\u5173\u952E\u7684\u95EE\u9898\u5373\u53EF\u3002\u800C\u5BF9\u4E8E\u90A3\u4E9B\u6240\u8C13\u7684 Code Smell \u95EE\u9898\uFF0C\u57FA\u4E8E\u7814\u53D1\u6210\u672C\u7684\u8003\u8651\uFF0C\u6211\u4EEC\u5E76\u4E0D\u4F1A\u8981\u6C42\u5B8C\u5168\u4FEE\u590D\u3002</p><p>\u63A5\u7740 CI/CD \u6D41\u6C34\u7EBF\u4F1A\u89E6\u53D1\u4EE3\u7801\u52A8\u6001\u6D4B\u8BD5\uFF0C\u5373\u5355\u5143\u6D4B\u8BD5\u3002\u8FD9\u91CC\uFF0C\u6211\u4EEC\u4E0D\u4EC5\u8981\u6C42\u5355\u5143\u6D4B\u8BD5\u80FD\u591F 100%\u901A\u8FC7\uFF0C\u5E76\u4E14\u4F1A\u8981\u6C42\u8FBE\u5230\u4E00\u5B9A\u7684\u4EE3\u7801\u8986\u76D6\u7387\u3002\u5728 eBay\uFF0C\u6211\u4EEC\u5BF9\u4E0D\u540C\u6A21\u5757\u7684\u4EE3\u7801\u8986\u76D6\u7387\u8981\u6C42\u4E5F\u4E0D\u4E00\u6837\uFF0C\u5E76\u6CA1\u6709\u4E00\u4E2A\u786C\u6027\u6307\u6807\u3002\u5176\u5B9E\uFF0C\u8FD9\u4E5F\u662F\u51FA\u4E8E\u7814\u53D1\u6210\u672C\u7684\u8003\u8651\u3002</p><p>\u901A\u5E38\u6765\u8BB2\uFF0C\u5BF9\u5E95\u5C42\u6A21\u5757\u4EE5\u53CA\u63D0\u4F9B\u516C\u5171\u670D\u52A1\u7684\u4E2D\u95F4\u4EF6\u7684\u4EE3\u7801\u8986\u76D6\u7387\u6307\u6807\u7684\u8981\u6C42\uFF0C\u4E00\u822C\u90FD\u4F1A\u6BD4\u8F83\u9AD8\u3002\u800C\u6211\u4EEC\u5BF9\u524D\u7AEF\u6A21\u5757\u7684\u8986\u76D6\u7387\u8981\u6C42\uFF0C\u5C31\u4F1A\u4F4E\u5F88\u591A\u3002</p><p><strong>\u95EE\u9898\u4E94\uFF1A\u9664\u4E86 Sonar\uFF0C\u4F60\u8FD8\u7528\u8FC7\u54EA\u4E9B\u9759\u6001\u4EE3\u7801\u626B\u63CF\u5DE5\u5177\uFF0C\u4F7F\u7528\u8FC7\u7A0B\u4E2D\u9047\u5230\u8FC7\u54EA\u4E9B\u95EE\u9898\uFF1F</strong></p><p>\u5728\u4E13\u680F\u7684\u7B2C 26 \u7BC7\u6587\u7AE0\u300A\u6DF1\u5165\u6D45\u51FA\u4E4B\u9759\u6001\u6D4B\u8BD5\u65B9\u6CD5\u300B\u4E2D\uFF0C\u6211\u548C\u4F60\u8BE6\u7EC6\u5206\u4EAB\u4E86\u4EBA\u5DE5\u9759\u6001\u6D4B\u8BD5\u65B9\u6CD5\u548C\u81EA\u52A8\u9759\u6001\u6D4B\u8BD5\u65B9\u6CD5\uFF0C\u6765\u5E2E\u4F60\u7406\u89E3\u7814\u53D1\u6D41\u7A0B\u4E0A\u662F\u5982\u4F55\u4FDD\u8BC1\u4EE3\u7801\u8D28\u91CF\u7684\u3002\u53E6\u5916\uFF0C\u6211\u4EE5 Sonar \u4E3A\u4F8B\uFF0C\u548C\u4F60\u5206\u4EAB\u4E86\u5982\u4F55\u642D\u5EFA\u81EA\u5DF1\u7684\u81EA\u52A8\u9759\u6001\u4EE3\u7801\u626B\u63CF\u65B9\u6848\uFF0C\u5E76\u4E14\u5E94\u7528\u5230\u9879\u76EE\u7684\u65E5\u5E38\u5F00\u53D1\u5DE5\u4F5C\u4E2D\u53BB\u3002</p><p>\u800C\u5728\u8FD9\u7BC7\u6587\u7AE0\u6700\u540E\uFF0C\u6211\u5E0C\u671B\u4F60\u5206\u4EAB\u7684\u662F\u9664\u4E86 Sonar \u4F60\u8FD8\u7528\u8FC7\u54EA\u4E9B\u9759\u6001\u4EE3\u7801\u626B\u63CF\u5DE5\u5177\uFF0C\u4F7F\u7528\u8FC7\u7A0B\u4E2D\u9047\u5230\u8FC7\u54EA\u4E9B\u95EE\u9898\u3002</p><p>\u5176\u5B9E\u4F18\u79C0\u7684\u4EE3\u7801\u9759\u6001\u626B\u63CF\u5DE5\u5177\u8FDC\u8FDC\u4E0D\u6B62 Sonar\uFF0C\u6BD4\u5982 Fortify SCA \u548C Checkmarx CxSuite \u7B49\u90FD\u662F\u5F88\u4F18\u79C0\u7684\u9759\u6001\u626B\u63CF\u5DE5\u5177\u3002\u81F3\u4E8E\u4F7F\u7528\u8FC7\u7A0B\u4E2D\u9700\u8981\u7684\u95EE\u9898\uFF0C\u6211\u89C9\u5F97\u4E3B\u8981\u6709\u8FD9\u4E48\u4E09\u4E2A\uFF1A</p><p>\u7B2C\u4E00\u662F\u8BEF\u62A5\u7387\u3002\u8FC7\u9AD8\u7684\u8BEF\u62A5\u7387\u4F1A\u964D\u4F4E\u5F00\u53D1\u4EBA\u5458\u5BF9\u6D4B\u8BD5\u5DE5\u5177\u7684\u4FE1\u4EFB\u5EA6\uFF0C\u800C\u4E14\u8FD8\u4F1A\u5F15\u5165\u5F88\u591A\u4EBA\u4E3A\u6807\u6CE8\u7684\u5DE5\u4F5C\u91CF\u3002</p><p>\u7B2C\u4E8C\u662F\u89C4\u5219\u5E93\u7684\u5B8C\u5907\u6027\u548C\u5B9E\u7528\u6027\u3002\u5F88\u591A\u65F6\u5019\u4F60\u4F1A\u53D1\u73B0\uFF0C\u6807\u51C6\u4EE3\u7801\u89C4\u5219\u5E93\u4E2D\u7684\u4E00\u4E9B\u89C4\u5219\u8BBE\u8BA1\u4E0D\u591F\u5408\u7406\uFF0C\u6709\u70B9\u6559\u6761\u4E3B\u4E49\u3002\u6BD4\u5982\uFF0C\u6709\u4E9B\u89C4\u5219\u5E93\u4F1A\u5F3A\u884C\u89C4\u5B9A\u4E00\u4E2A\u51FD\u6570\u7684\u4EE3\u7801\u884C\u6570\u4E0D\u80FD\u8D85\u8FC7 200 \u884C\uFF0C\u4ECE\u4EE3\u7801\u7684\u6A21\u5757\u5316\u548C\u6613\u7EF4\u62A4\u6027\u89D2\u5EA6\u6765\u8BB2\uFF0C\u8FC7\u957F\u7684\u51FD\u6570\u5B9E\u73B0\u4F53\u7684\u786E\u4E0D\u5229\u4E8E\u4EE3\u7801\u5065\u5EB7\u3002\u4F46\u662F\uFF0C\u4E5F\u4E0D\u80FD\u5B8C\u5168\u4E00\u5200\u5207\uFF0C\u6BD5\u7ADF\u6709\u4E9B\u51FD\u6570\u5C31\u662F\u5B9E\u73B0\u8D77\u6765\u6BD4\u8F83\u590D\u6742\u3002\u6240\u4EE5\uFF0C\u5F88\u591A\u65F6\u5019\u6211\u4EEC\u9700\u8981\u5BF9\u6807\u51C6\u89C4\u5219\u5E93\u8FDB\u884C\u6DF1\u5C42\u6B21\u5730\u88C1\u526A\uFF0C\u4EE5\u66F4\u597D\u5730\u9002\u5E94\u4F01\u4E1A\u7684\u5B9E\u9645\u60C5\u51B5\u3002</p><p>\u7B2C\u4E09\u662F\u81EA\u5B9A\u4E49\u89C4\u5219\u7684\u96BE\u6613\u7A0B\u5EA6\u3002\u867D\u7136\u5F88\u591A\u9759\u6001\u4EE3\u7801\u5DE5\u5177\u90FD\u63D0\u4F9B\u4E86\u89C4\u5219\u7F16\u8F91\u5668\uFF0C\u6765\u65B9\u4FBF\u4F60\u5B9E\u73B0\u81EA\u5DF1\u7684\u89C4\u5219\uFF0C\u4F46\u662F\u8FD9\u4E9B\u89C4\u5219\u7F16\u8F91\u5668\u7684\u4F7F\u7528\u65B9\u6CD5\u548C\u8BED\u6CD5\u7684\u5B66\u4E60\u6210\u672C\u6BD4\u8F83\u9AD8\uFF0C\u5BF9\u521D\u5B66\u8005\u4E0D\u591F\u53CB\u597D\u3002</p><p>\u95EE\u9898\u516D\uFF1A\u5728\u5355\u5143\u6D4B\u8BD5\u8FC7\u7A0B\u4E2D\uFF0C\u4F60\u90FD\u9047\u5230\u8FC7\u54EA\u4E9B\u95EE\u9898\uFF0C\u53C8\u662F\u5982\u4F55\u89E3\u51B3\u7684\u5462\uFF1F \u5728\u4E13\u680F\u7684\u7B2C 27 \u7BC7\u6587\u7AE0\u300A\u6DF1\u5165\u6D45\u51FA\u4E4B\u52A8\u6001\u6D4B\u8BD5\u65B9\u6CD5\u300B\u4E2D\uFF0C\u6211\u548C\u4F60\u5206\u4EAB\u4E86\u4EBA\u5DE5\u52A8\u6001\u6D4B\u8BD5\u65B9\u6CD5\u548C\u81EA\u52A8\u52A8\u6001\u6D4B\u8BD5\u65B9\u6CD5\u3002\u56E0\u4E3A\u81EA\u52A8\u52A8\u6001\u65B9\u6CD5\u5E76\u4E0D\u80FD\u7406\u89E3\u4EE3\u7801\u903B\u8F91\uFF0C\u6240\u4EE5\u4EC5\u4EC5\u88AB\u7528\u4E8E\u53D1\u73B0\u5F02\u5E38\u3001\u5D29\u6E83\u548C\u8D85\u65F6\u8FD9\u7C7B\u201C\u6709\u7279\u5F81\u201D\u7684\u9519\u8BEF\uFF0C\u800C\u5BF9\u4E8E\u4EE3\u7801\u903B\u8F91\u529F\u80FD\u7684\u6D4B\u8BD5\uFF0C\u4E3B\u8981\u8FD8\u662F\u8981\u4F9D\u9760\u4EBA\u5DE5\u52A8\u6001\u65B9\u6CD5\u3002</p><p>\u5728\u8FD9\u7BC7\u6587\u7AE0\u6700\u540E\uFF0C\u6211\u5E0C\u671B\u4F60\u5206\u4EAB\u7684\u662F\uFF0C\u9664\u4E86\u6211\u5728\u6587\u4E2D\u63D0\u5230\u7684\u51E0\u4E2A\u5355\u5143\u6D4B\u8BD5\u7684\u96BE\u70B9\u95EE\u9898\uFF0C\u4F60\u8FD8\u9047\u5230\u8FC7\u54EA\u4E9B\u95EE\u9898\uFF0C\u53C8\u662F\u5982\u4F55\u89E3\u51B3\u7684\u3002</p><p>\u8FD9\u91CC\uFF0C\u6211\u60F3\u518D\u548C\u4F60\u5206\u4EAB\u6211\u66FE\u5728\u5355\u5143\u6D4B\u8BD5\u4E2D\u9047\u5230\u8FC7\u7684\u95EE\u9898\u3002</p><p>\u5355\u5143\u6D4B\u8BD5\u7684\u96BE\u70B9\u4E2D\u8F83\u4E3A\u5178\u578B\u7684\u5C31\u662F\u5BF9\u5185\u90E8\u8F93\u5165\u7684\u63A7\u5236\u3002\u5BF9\u4E8E\u5185\u90E8\u8F93\u5165\u7684\u63A7\u5236\u6709\u6570\u5341\u79CD\u4E0D\u540C\u7684\u573A\u666F\uFF0C\u8FD9\u91CC\u6211\u5C31\u4E3E\u4E00\u4E2A\u4F8B\u5B50\uFF0C\u610F\u5728\u629B\u7816\u5F15\u7389\u3002</p><p>\u9996\u5148\u4E3A\u4E86\u8FBE\u5230\u8F83\u9AD8\u7684\u6D4B\u8BD5\u4EE3\u7801\u8986\u76D6\u7387\uFF0C\u5982\u679C\u4EE3\u7801\u4E2D\u5305\u62EC\u4E86 if-else \u5206\u652F\uFF0C\u90A3\u4E48\u6211\u4EEC\u7684\u6D4B\u8BD5\u5C31\u9700\u8981\u5206\u522B\u6267\u884C\u5230\u8FD9\u4E24\u4E2A\u5206\u652F\u3002\u5047\u8BBE\uFF0C\u73B0\u5728\u6709\u4E00\u4E2A if-else \u5206\u652F\u662F\u6839\u636E malloc \u8FD9\u4E2A\u5185\u5B58\u5206\u914D\u51FD\u6570\u7684\u7ED3\u679C\u8FDB\u884C\u4E0D\u540C\u7684\u5904\u7406\uFF0C\u5982\u679C\u5185\u5B58\u5206\u914D\u6210\u529F\u4E86\uFF0C\u5C31\u6267\u884C A \u903B\u8F91\uFF0C\u5982\u679C\u6267\u884C\u5931\u8D25\u4E86\u5C31\u6267\u884C B \u903B\u8F91\u3002</p><p>\u90A3\u4E48\uFF0C\u5728\u505A\u5355\u5143\u6D4B\u8BD5\u7684\u65F6\u5019\uFF0C\u901A\u5E38\u60C5\u51B5\u4E0B\u5F88\u5BB9\u6613\u8986\u76D6\u5185\u5B58\u5206\u914D\u6210\u529F\u7684\u573A\u666F\uFF0C\u4F46\u662F\u60F3\u8981\u5B9E\u73B0\u201C\u53EF\u63A7\u201D\u7684\u5185\u5B58\u5206\u914D\u5931\u8D25\u5C31\u6BD4\u8F83\u56F0\u96BE\u4E86\u3002\u56E0\u4E3A malloc \u662F\u4E2A\u5E95\u5C42\u7CFB\u7EDF\u51FD\u6570\uFF0C\u6839\u672C\u65E0\u6CD5\u5BF9\u5176\u63A7\u5236\u3002</p><p>\u4E3A\u4E86\u89E3\u51B3\u8FD9\u4E2A\u95EE\u9898\uFF0C\u6211\u4EEC\u5C31\u53EF\u4EE5\u91C7\u7528\u6869\u51FD\u6570\u7684\u601D\u60F3\uFF0C\u5F15\u5165\u4E00\u4E2A malloc \u7684\u6869\u51FD\u6570\uFF0C\u5728\u8FD9\u4E2A\u6869\u51FD\u6570\u7684\u5185\u90E8\u518D\u53BB\u8C03\u7528\u771F\u6B63\u7684\u7CFB\u7EDF malloc \u51FD\u6570\uFF0C\u5982\u679C\u9700\u8981\u6A21\u62DF\u771F\u6B63\u7684 malloc \u51FD\u6570\u7684\u5931\u8D25\uFF0C\u5C31\u5728\u6869\u51FD\u6570\u91CC\u9762\u76F4\u63A5\u8FD4\u56DE malloc \u51FD\u6570\u5931\u8D25\u7684\u8FD4\u56DE\u503C\uFF0C\u6765\u8FBE\u5230\u6A21\u62DF\u771F\u6B63 malloc \u51FD\u6570\u5931\u8D25\u573A\u666F\u7684\u76EE\u7684\u3002\u8FD9\u6837\u5C31\u80FD\u5728\u88AB\u6D4B\u51FD\u6570\u4E2D\u901A\u8FC7\u53EF\u63A7\u7684\u65B9\u5F0F\uFF0C\u6765\u6A21\u62DF\u7CFB\u7EDF\u5E95\u5C42\u51FD\u6570\u7684\u8FD4\u56DE\u503C\u4E86\u3002</p>',60);function t(e,a){return P}var n=p(I,[["render",t],["__file","57.html.vue"]]);export{n as default};
